#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
apply_collaboration_finitions.py — Finitions UI du module collaboration :
  #1 selecteur de partage des commentaires dans le dialogue de partage (§14),
  #2 droits fins par membre (mesurer/commenter/repondre/valider) ecran equipe (§17),
  #3 vue partagee publique : viewer CAO lecture seule + marqueurs + liste des
     commentaires (+ proxy fichier partage same-origin).
A lancer a la racine du repo (Codespace) :  python3 apply_collaboration_finitions.py
Ecrit -> next build (STOP si echec) -> commit + push.
"""
import base64, json, os, subprocess, sys
FILES=json.loads(r'''{
"src/app/projects/[id]/access/page.tsx": "",
"src/app/projects/[id]/team/page.tsx": "",
"src/app/shared/[id]/page.tsx": "",
"src/components/SharedCadViewer.tsx": "",
"src/app/api/shared/[id]/files/[fileId]/raw/route.ts": ""
}''')
def run(*a, check=True):
    print("+"," ".join(a)); return subprocess.run(a, check=check)
def cfg(k): return subprocess.run(["git","config",k],capture_output=True,text=True).stdout.strip()
def main():
    if not os.path.isfile("package.json"): sys.exit("Lance a la racine du repo.")
    for p,b in FILES.items():
        os.makedirs(os.path.dirname(p),exist_ok=True); open(p,"wb").write(base64.b64decode(b)); print("  ecrit:",p)
    print(">>> Verification build...")
    if run("npx","next","build",check=False).returncode!=0: sys.exit("!!! build ECHOUE, rien pousse.")
    if not cfg("user.email"): run("git","config","user.email","bilnov-bot@users.noreply.github.com")
    if not cfg("user.name"):  run("git","config","user.name","BILNOV bot")
    run("git","add","-A")
    run("git","commit","-m","feat(cad): finitions collaboration (partage filtre UI, droits par membre, vue partagee avec viewer + commentaires)")
    run("git","push"); print("\nOK. Push -> Vercel deploie.")
if __name__=="__main__": main()
